scwin.vCurDate;
scwin.vQryStDt;
scwin.vQryEndDt;
scwin.isFilter;
scwin.ds_detail_UseFilter;
scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "SD070", compID : "acb_taxnClsCd" }, // 부가세구분
        { grpCd : "FS500", compID : "gr_out:dcsnClsCd" } // 부가세구분
    ];
    $c.data.setCommonCode(codeOptions, scwin.searchCallBackCombo);

    scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");  				// 서버를 기준으로 현재 날짜 반환
	scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
	scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + $c.date.getLastDateOfMonth(scwin.vCurDate.substring(0, 6));  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)
    scwin.isFilter 	= true;

};

scwin.searchCallBackCombo = function(){
    acb_taxnClsCd.setSelectedIndex(0);

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

        ica_qryConDtFm.setValue(scwin.vQryStDt);
        ica_qryConDtTo.setValue(scwin.vQryEndDt);
        acb_qryDtConKnd.setValue("CERTI");

        $c.gus.cfDisableBtnOnly([btn_save]);

        $c.gus.cfEnableObj(ica_slipCloseYm, false);
        $c.gus.cfEnableObj(ica_taxCloseYm, false);

        ed_homeClntNo.focus();

        // $p.setTimeout(function() {
        //     ed_homeClntNo.setValue('236459');
        //     ica_qryConDtFm.setValue('20130101');
        //     ica_qryConDtTo.setValue('20260131');
        //     acb_qryDtConKnd.setValue("SPPLY");

        //     ed_homeClntNo.setValue('227930');
        //     ica_qryConDtFm.setValue('20250630');
        //     ica_qryConDtTo.setValue('20250630');
        //     acb_qryDtConKnd.setValue("CERTI");

        //     ed_homeClntNo.focus();
        //     ed_homeClntNo.blur();
        // }, {"delay":50});
    }, {"delay":50});
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    //validation check
    if(!await $c.gus.cfValidate([ed_homeClntNo])){
        return;
    }

    //조회시작일자가 더 클경우 체크
    if (!await $c.gus.cfIsAfterDate(ica_qryConDtFm.getValue(), ica_qryConDtTo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }
    if (acb_qryDtConKnd.getValue() == "CERTI"){
        $c.sbm.execute(sbm_retrieve);

    } else if (acb_qryDtConKnd.getValue() == "SPPLY" || acb_qryDtConKnd.getValue() == "POST"){
        $c.sbm.execute(sbm_eachSellingEvidenceList);

    }
};

//-------------------------------------------------------------------------
// 하단그리드 조회
//-------------------------------------------------------------------------
scwin.f_DetailRetrieve = function (row) {
    ds_condition_con.set("slipNo", ds_out.getCellData(row, "slipNo")); 
    $c.sbm.execute(sbm_detail_retrieve);
};

//-------------------------------------------------------------------------
// 조회조건 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search,null);

    ica_qryConDtFm.setValue(scwin.vQryStDt);
    ica_qryConDtTo.setValue(scwin.vQryEndDt);
    acb_taxnClsCd.setSelectedIndex(0);
    acb_qryDtConKnd.setValue("CERTI");

    ed_homeClntNo.focus();
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if(ds_out.getRowCount() < 1 || ds_detail.getRowCount() < 1){
        return;
    }  	
    // $c.gus.cfCopyDataSetHeader(ds_out, ds_saveOut);
    ds_saveOut.removeAll();

    var	transRow;
    var chkCnt = 0;
    for(var i = 0 ;i < ds_out.getRowCount() ; i++){
        if(ds_out.getCellData(i, "choice") == "T"){
            if(ds_out.getCellData(i, "spplyDt") == null || ds_out.getCellData(i, "spplyDt") == ""){
                await $c.gus.cfAlertMsg("청구세금계산서 내역의 "+(i+1)+"번째 데이터에 공급일자는 필수입력 항목입니다.");
                return;
            }

            var isDate = $c.date.isDate(ds_out.getCellData(i, "spplyDt"), false);
            if(!isDate){
                await $c.gus.cfAlertMsg("청구세금계산서 내역의 "+(i+1)+"번째 데이터에 공급일자는 유효한 날짜 형식이 아닙니다.");
                return;
            }
            if(ds_out.getCellData(i, "slipDt") == null || ds_out.getCellData(i, "slipDt") == ""){
                await $c.gus.cfAlertMsg("청구세금계산서 내역의 "+(i+1)+"번째 데이터에 전표일자는 필수입력 항목입니다.");
                return;
            }

            var isDate2 = $c.date.isDate(ds_out.getCellData(i, "slipDt"), false);
            if(!isDate2){
                await $c.gus.cfAlertMsg("청구세금계산서 내역의 "+(i+1)+"번째 데이터에 전표일자는 유효한 날짜 형식이 아닙니다.");
                return;
            }
            if(ds_out.getCellData(i, "goods") == null || ds_out.getCellData(i, "goods") == ""){
                await $c.gus.cfAlertMsg("청구세금계산서 내역의 "+(i+1)+"번째 데이터에 품명은 필수입력 항목입니다.");
                return;
            }
            // 세금계산서거 발행되었으면....
            if(ds_out.getCellData(i, "slipNo") != null && ds_out.getCellData(i, "slipNo") != ""){
                await $c.gus.cfAlertMsg("청구세금계산서 내역의 "+(i+1)+"번째 데이터는 매출증빙 내역이 있는 자료입니다.\n일괄저장 할 수 없습니다.");
                return;
            }
            chkCnt++;
            ds_saveOut.setJSON([ds_out.getAllJSON()[i]], true);
            ds_saveOut.setCellData(chkCnt, "curRow", i);		
            // transRow = ds_out.ExportData(i,1,false);
            // ds_saveOut.ImportData(transRow);
        }
    }
    ds_saveOut.modifyAllStatus("U");
    scwin.isFilter = false;
    // gr_detail.DataID = '';
    // gr_detail.DataID = 'ds_detail';	 
    scwin.ds_detail_filter();

    // $c.gus.cfCopyDataSetHeader(ds_detail, ds_saveDetail);
    ds_saveDetail.removeAll();

    var	transRow2;
    var chkCnt2 = 0;
    var jsonData = [];
    for(var i = 0 ; i < ds_detail.getRowCount() ; i++){
        if(ds_detail.getCellData(i, "choice") == "T"){		
            // ds_out.getMatchedIndex(columnInfo, data, exactMatch, startRowIndex, lastRowIndex)
            var idxArr = ds_out.getMatchedIndex("bilgClntNo", ds_detail.getCellData(i, "bilgClntNo"));
            if (idxArr.length > 0){
                if (ds_out.getCellData(idxArr[0], "choice") == "T") {
                    jsonData.push(ds_detail.getAllJSON()[i]);
                    chkCnt2++;
                }
            }
            // if(ds_out.getCellData(ds_out.getCellData('bilgClntNo' ,ds_detail.getCellData(i, "bilgClntNo")), "choice") == "T"){
            //     // transRow2 = ds_detail.ExportData(i,1,false);
            //     // ds_saveDetail.ImportData(transRow2);
            //     jsonData.push(ds_detail.getAllJSON()[i]);
            //     chkCnt2++;
            // }
        }
    }
    ds_saveDetail.setJSON(jsonData);
    ds_saveDetail.modifyAllStatus("U");

    scwin.isFilter = true;
    // gr_detail.DataID = '';
    // gr_detail.DataID = 'ds_detail';	 
    scwin.ds_detail_filter();

    if(chkCnt < 1 || chkCnt2 < 1){
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007,["저장할 자료"]);
        return;
    }

    if(!await $c.win.confirm(MSG_CM_CRM_001)) return;

    $c.sbm.execute(sbm_save);
};


//-------------------------------------------------------------------------
// 팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    // 공통POP-UP -> 요청화면
    var rtnList  = new Array();
    switch (disGubun) {
        case 1:
            //소속거래처
            udc_homeClnt.setSelectId('retrieveSubsidaryClntList');
            udc_homeClnt.cfCommonPopUp(scwin.udc_homeClnt_callBackFunc	    	// XML상의 SELECT ID
                                    ,pCode								// 화면에서의 ??? Code Element의	Value
                                    ,pName								// 화면에서의 ??? Name Element의	Value
                                    ,pClose								// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,'5'								// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null								// Title순서
                                    ,'150,170'  		    			// 보여주는 각 컬럼들의 폭
                                    ,null								// 컬럼중에서 숨기는	컬럼 지정
                                    ,null								// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null								// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null								// POP-UP뛰을때 우도우의	사용자 정의	높이
                                    ,null								// 윈도우 위치 Y좌표
                                    ,null								// 윈도우 위치 X좌표
                                    ,null								// 중복체크여부	("F")
                                    ,pAllSearch							// 전체검색허용여부	("F")
                                    ,"소속거래처,거래처코드,거래처명"			// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case 2:
            udc_vehclNo.setSelectId('retrieveSubsidaryVehclList');
            udc_vehclNo.cfCommonPopUp(scwin.udc_vehclNo_callBackFunc           // XML상의 SELECT ID  
                                     ,pCode                   // 화면에서의 ??? Code Element의  Value
                                     ,pName                   // 화면에서의 ??? Name Element의  Value
                                     ,pClose                  // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                                     ,null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                                     ,null                   // Title순서  
                                     ,null                   // 보여주는 각 컬럼들의 폭    
                                     ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                                     ,null                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                     ,"400"                  // POP-UP뛰을때 원도우의   사용자 정의  폭
                                     ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                                     ,null                   // 윈도우 위치 Y좌표   
                                     ,null                   // 윈도우 위치 X좌표
                                     ,null                   // 중복체크여부   ("F")
                                     ,pAllSearch                 // 전체검색허용여부 ("F")
                                     ,"차량번호,차량단축코드,차량번호"             // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            ); 	
            break;
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

  	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
	    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
	else
	    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 세금계산서 출력
//-------------------------------------------------------------------------
scwin.f_Print = async function () {
    var param = "";
    var printCnt = 0;

    for (var i = 0 ; i < ds_out.getRowCount(); i++) {
        if (ds_out.getCellData(i, "printChk") == "T") {
            param = param + ",TO_CHAR(" + ds_out.getCellData(i, "sellVatNo") + ")";  // 계산서번호
            printCnt++; 
        }
    }

    if (printCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["발행할 세금계산서"]);  // @을(를) 선택하십시오.
        return;
    }

    // // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
    // var odiParam = new ODIParam("fi_401_01_09p");
    // odiParam.add("pchsSellCls", param.substring(1));
    // // OZ 뷰어에 대한 설정(상세 설정은 'oz report viewer guide.pdf'를 참조)
    // var viewerParam = new ViewerParam();
    // //viewerParam.add("viewer.zoom", "100");
    // //viewerParam.add("print.mode", "silent");  // 프린트 설정창 없게
    // viewerParam.add("viewer.mode", "preview");  // 미리보기
    // //viewerParam.add("viewer.mode", "print");  // 미리보기 없이 바로 출력  20130617
    // //viewerParam.add("viewer.useprogressbar", "false");  // PROGRESSBAR 안보이게
    // // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
    // var formParam = new FormParam();
    // //formParam.add("form1", "폼1");
    // cfOZReport("chb_printCheck", "chb_previewCheck", "/ac/fi/taxbiz/vatctrl/fi_401_01_09p_2.ozr", odiParam, viewerParam, formParam);

    // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
    // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
    let data = {
        odiName : "fi_401_01_09p",
        reportName: "/ac/fi/taxbiz/vatctrl/fi_401_01_09p_2.ozr",
        odiParam : {
            pchsSellCls : param.substring(1)
        },
        viewerParam : {
            useprogressbar : true, // 프로그레스바 쓸지 말지
            zoom : 90, // 배율 설정
            "viewer.mode" : "preview"
        },
        formParam : {}
    };
    let opts = {
        id          : "ozReportPopup",
        popupName   : "오즈 리포트",
        modal       : true,
        type        : "browserPopup",
        width       : 1000,
        height      : 600,
        title       : "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

