scwin.sbm_save_submitdone = async function (e) {
    // ds_outSellingEvidenceList event=OnLoadCompleted(rowcnt)
    var rowCnt1 = ds_outSellingEvidenceList.getRowCount();
    for(var i = 0 ;i < rowCnt1 ; i++){
		ds_out.setCellData(ds_outSellingEvidenceList.getCellData(i, "curRow"), "sellVatNo", ds_outSellingEvidenceList.getCellData(i, "sellVatNo"));
		ds_out.setCellData(ds_outSellingEvidenceList.getCellData(i, "curRow"), "slipNo", ds_outSellingEvidenceList.getCellData(i, "slipNo"));
		ds_out.setCellData(ds_outSellingEvidenceList.getCellData(i, "curRow"), "dcsnClsNm", ds_outSellingEvidenceList.getCellData(i, "dcsnClsNm"));
		if(i == (rowCnt1 - 1)){
			ds_out.setRowPosition(ds_outSellingEvidenceList.getCellData(i, "curRow"));
			ds_out.setCellData(ds_outSellingEvidenceList.getCellData(i, "curRow"), "choice", "F");
            gr_out.setCellReadOnly(i, 'choice', true);
            var info = {
                inputType : "text",
                // options : {
                //     selectedData : false,
                //     viewType: "icon",
                //     chooseOption: true
                // },
                // itemSet : {
                //     nodeset: "data:dlt_dataList1", 
                //     label: "label",
                //     value: "value"
                // }
            }
            gr_detail.setCellInputType(i, 'choice', info);
			// ds_out.ColumnProp('choice', 'Edit') = "None";
			// gr_detail.ColumnProp('choice', 'Show') = "false";

            gr_detail.setFocusedCell(i, "choice", true);
			//$c.gus.cfDisableBtnOnly([btn_save]);
		}
	}

    var rowCnt2 = ds_billingCommonMessage.getRowCount();
    // ds_billingCommonMessage event=OnLoadCompleted(rowcnt)
    if (rowCnt2 < 1){
		// cfShowError(ds_billingCommonMessage);
	}else{
		await $c.gus.cfAlertMsg(ds_billingCommonMessage.getCellData(0, "msg"));
	}

    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
	scwin.f_Retrieve();
};

