scwin.ds_out_onloadCompleted = async function(){
    gr_out.setColumnStyle("button", "text-decoration", "underline");
    gr_out.setColumnStyle("button", "color", "blue");
    gr_out.setColumnStyle("button", "cursor", "pointer");

    // cfHideDSWaitMsg(gr_out);
	// cfShowTotalRows(totalRows, rowcnt);
    var rowCnt = ds_out.getRowCount();
    txt_totalRows.setValue(rowCnt);
    txt_totalRows2.setValue("0");

	if(rowCnt > 0){
        ica_slipCloseYm.setValue(ds_out.getCellData(0, "slipCloseYm"));				//회계마감월
        ica_taxCloseYm.setValue(ds_out.getCellData(0, "taxCloseYm"));				//세무마감월

		if(ds_out.getCellData(0, "slipNo") != null && ds_out.getCellData(0, "slipNo") != ""){
			scwin.f_DetailRetrieve("0");
			scwin.ds_detail_UseFilter = false;
			$c.gus.cfDisableBtnOnly([btn_save]);

            gr_out.setColumnReadOnly("choice", true);
            gr_out.setColumnReadOnly("printChk", false);
		}else{	
			scwin.ds_detail_UseFilter = true;
			$c.gus.cfEnableBtnOnly([btn_save]);

            gr_out.setColumnReadOnly("choice", false);
            gr_out.setColumnReadOnly("printChk", true);

		}
	}else{
        ica_slipCloseYm.setValue("");				//회계마감월
        ica_taxCloseYm.setValue("");				//세무마감월

		$c.gus.cfDisableBtnOnly([btn_save]);
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
	    ds_detail.removeAll();		
	}
};

