scwin.ds_detail_filter = async function(){
    // if(scwin.isFilter && scwin.ds_detail_UseFilter) {
    if(scwin.isFilter) {
		var v_val = ds_out.getCellData(ds_out.getRowPosition(), "bilgClntNo");
