		// 	return true;
		// }else{
		//    	return false;
		// }

        // 필터링을 해제 
        // GridView의 'dept' 컬럼의 모든 데이터를 표시
        ds_detail.clearFilter();

        // GridView의 'dept' 컬럼을 IT로 필터링
        // GridView의 'dept' 컬럼이 IT인 행만 표시됨
        ds_detail.setColumnFilter( {type:'row', colIndex:'bilgClntNo', key:v_val, condition:'and'});


	}else{
        ds_detail.clearFilter();
		// return true;
	}
    txt_totalRows2.setValue(ds_detail.getRowCount());
};

scwin.gr_out_oncellclick = async function (row, columnIndex, colid) {
    if(colid == "button"){
        // var	transRow
        // $c.gus.cfCopyDataSetHeader(ds_out, ds_sellingEvidence);
        // transRow = ds_out.ExportData(row,1,false);
        // ds_sellingEvidence.ImportData(transRow);
        // ds_sellingEvidence.getCellData(1, "curRow") = row;

        ds_sellingEvidence.setJSON([ds_out.getAllJSON()[row]]);
        ds_sellingEvidence.setCellData(0, "curRow", row);

        $c.gus.cfCopyDataSet(ds_detail, ds_commonCopyList);
        ds_commonCopyList.removeAll();

        for (var i = 0; i < ds_detail.getAllFilteredJSON().length; i++){
            ds_commonCopyList.setRowJSON(i, ds_detail.getAllFilteredJSON()[i]);    
        }

        // var valueObject = new Object();
        // valueObject.sellingEvidence = ds_sellingEvidence;
        // valueObject.commonList = ds_commonCopyList;

        //상세화면 호출
        // var result = modal("ja_210_01_02p.jsp", valueObject, 800, 560);	   
        let win_url = "/ui/ja/dn/bilg/ja_210_01_02p.xml";
        let data = {
            //   "sellingEvidence"     : ds_sellingEvidence 
            // , "commonList"          : ds_commonCopyList
        };
        let opts = {
            id : "detailPop"
            , popupName : "세금계산서 개별 생성"
            , modal : true
            , type : "browserPopup"
            , width : 1200
            , height : 800
            , title : "세금계산서 개별 생성"
        };
        var result = await $c.win.openPopup(win_url, opts, data);

        if (acb_qryDtConKnd.getValue() == "CERTI"){
            $c.sbm.execute(sbm_retrieve);

        } else if (acb_qryDtConKnd.getValue() == "SPPLY" || acb_qryDtConKnd.getValue() == "POST"){
            $c.sbm.execute(sbm_eachSellingEvidenceList);

        }	
    }else if(colid != "button"){
        if(ds_out.getCellData(row, "slipNo") != null && ds_out.getCellData(row, "slipNo") != ""){
            scwin.f_DetailRetrieve(row);
        }
    }
};

scwin.dataSetInfo = function (dataSet, isDebug) {
    if(isDebug == true){
        var obj = dataSet;
        var fullId = dataSet.id;
        var objId = fullId.substring(fullId.lastIndexOf("ds_"));
        var str = "[" + objId + "]" ;
        str += "\r\n";

        for (var i = 0; i < dataSet.getColumnCount(); i++) {
            var dataInfo = dataSet.getColumnInfo(i); 
            var id = dataInfo.id;
            var dataType = dataInfo.dataType;
            var name = dataInfo.name;

            var colType = "";
            switch (dataType) {
                case "text" : 
                    colType = "String";
                    break;
                case 2 : 
                    colType = "Integer";
                    break;
                case "number" : 
                    colType = "Decimal";
                    break;
                case 4 : 
                    colType = "Date";
                    break;
                case 5 : 
                    colType = "URL";
                    break;				
            }

            str += id + " " + colType + " : " + dataSet.getCellData(0, id) + " ";		
            str += "\r\n";
        }

        console.log(str);
    }
};

